protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");
        entity.HasIndex(p => p.Sku);

        // EF Core 9 changed the default discriminator property from
        // "Discriminator" to "$type". Preserve the old name so existing
        // 500K documents (and direct SQL queries that filter on
        // c.Discriminator) keep working.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 no longer prepends the discriminator to the id
        // (was "Product|123", now just "123"). Preserve the old format
        // so existing documents remain readable.
        entity.HasPartitionKey(p => p.Id);
        entity.Property(p => p.Id).ToJsonPropertyName("id");
        entity.UseETagConcurrency();
    });
}

protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
{
    base.OnConfiguring(optionsBuilder);

    // EF Core 9 Cosmos provider throws on synchronous I/O by default.
    // Re-enable sync APIs until callers are migrated to async.
    optionsBuilder.ConfigureWarnings(w =>
        w.Ignore(Microsoft.EntityFrameworkCore.Diagnostics.CosmosEventId.SyncNotSupported));
}

